package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Date;

class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateType;

    @BeforeEach
    void setUp() throws Exception {
        dateType = mock(DefaultDateTypeAdapter.DateType.class);
        // Use reflection to access the private constructor
        var constructor = DefaultDateTypeAdapter.class.getDeclaredConstructor(DefaultDateTypeAdapter.DateType.class, String.class);
        constructor.setAccessible(true);
        adapter = (DefaultDateTypeAdapter<Date>) constructor.newInstance(dateType, "yyyy-MM-dd");
    }

    @Test
    void read_shouldReturnNull_whenJsonTokenIsNull() throws IOException {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.NULL);

        Date result = adapter.read(in);

        verify(in).nextNull();
        assertNull(result);
    }

    @Test
    void read_shouldReturnDeserializedDate() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.STRING);
        Date expectedDate = new Date();

        // Spy the adapter instance
        DefaultDateTypeAdapter<Date> spyAdapter = Mockito.spy(adapter);

        // Use reflection to access the private method deserializeToDate
        Method deserializeToDateMethod = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeToDateMethod.setAccessible(true);

        // Mock the private method call using doAnswer
        doAnswer(invocation -> expectedDate).when(spyAdapter).read(any(JsonReader.class));
        // Instead of mocking read, mock deserializeToDate via reflection proxy:
        // We need to mock the private method call inside read(), so we override it via spy.
        // But Mockito cannot mock private methods directly.
        // So instead, we use a partial mock that calls the private method via reflection and mock that.

        // To mock deserializeToDate, we use spy and a wrapper method:
        // We create a helper subclass for this test:
        class TestAdapter extends DefaultDateTypeAdapter<Date> {
            TestAdapter(DefaultDateTypeAdapter.DateType<Date> dt, String pattern) throws Exception {
                super(dt, pattern);
            }
            @Override
            public Date read(JsonReader in) throws IOException {
                if (in.peek() == JsonToken.NULL) {
                    in.nextNull();
                    return null;
                }
                // Instead of calling private method, call mocked method:
                return dateType.deserialize(expectedDate);
            }
        }

        // Create instance of helper subclass
        var testAdapter = new TestAdapter(dateType, "yyyy-MM-dd");
        var spyTestAdapter = Mockito.spy(testAdapter);

        when(dateType.deserialize(expectedDate)).thenReturn(expectedDate);

        // We mock deserializeToDate by overriding read() in TestAdapter to return expectedDate directly
        Date actual = spyTestAdapter.read(in);

        verify(dateType).deserialize(expectedDate);
        assertEquals(expectedDate, actual);
    }
}
